import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import CourseSection from '../components/CourseSection';
import AboutSection from '../components/AboutSection';
import StatsSection from '../components/StatsSection';
import NewsSection from '../components/NewsSection';
import ContactSection from '../components/ContactSection';
import Hero from '../components/Hero';
import '../styles/HomePage.css';

const HomePage = () => {
    const [activeFilter, setActiveFilter] = useState('all');

    // Add animation effects when components enter viewport
    useEffect(() => {
        // Intersection Observer for scroll animations
        const observerOptions = {
            threshold: 0.1,
            rootMargin: '0px 0px -50px 0px'
        };

        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');

                    // Add stagger animation to children
                    const children = entry.target.querySelectorAll('.animate-child');
                    children.forEach((child, index) => {
                        setTimeout(() => {
                            child.classList.add('visible');
                        }, index * 100);
                    });
                }
            });
        }, observerOptions);

        // Observe all sections
        const sections = document.querySelectorAll('.home-page .section');
        sections.forEach(section => observer.observe(section));

        // Add parallax effect to shapes
        const handleScroll = () => {
            const scrolled = window.pageYOffset;
            const shapes = document.querySelectorAll('.parallax-shape');

            shapes.forEach(shape => {
                const speed = shape.dataset.speed || 0.5;
                const yPos = -(scrolled * speed);
                shape.style.transform = `translateY(${yPos}px)`;
            });
        };

        window.addEventListener('scroll', handleScroll);

        return () => {
            window.removeEventListener('scroll', handleScroll);
            sections.forEach(section => observer.unobserve(section));
        };
    }, []);

    const handleFilterClick = (filter) => {
        setActiveFilter(filter);
        // Add ripple effect
        const buttons = document.querySelectorAll('.filter-btn');
        buttons.forEach(btn => btn.classList.remove('active'));
        event.target.closest('.filter-btn').classList.add('active');
    };

    return (
        <div className="home-page">
            {/* Hero Section */}
            <Hero />

            {/* Decorative Shape Divider */}
            <div className="shape-divider shape-divider-1">
                <svg viewBox="0 0 1200 120" preserveAspectRatio="none">
                    <path d="M0,0V46.29c47.79,22.2,103.59,32.17,158,28,70.36-5.37,136.33-33.31,206.8-37.5C438.64,32.43,512.34,53.67,583,72.05c69.27,18,138.3,24.88,209.4,13.08,36.15-6,69.85-17.84,104.45-29.34C989.49,25,1113-14.29,1200,52.47V0Z" opacity=".25"></path>
                    <path d="M0,0V15.81C13,36.92,27.64,56.86,47.69,72.05,99.41,111.27,165,111,224.58,91.58c31.15-10.15,60.09-26.07,89.67-39.8,40.92-19,84.73-46,130.83-49.67,36.26-2.85,70.9,9.42,98.6,31.56,31.77,25.39,62.32,62,103.63,73,40.44,10.79,81.35-6.69,119.13-24.28s75.16-39,116.92-43.05c59.73-5.85,113.28,22.88,168.9,38.84,30.2,8.66,59,6.17,87.09-7.5,22.43-10.89,48-26.93,60.65-49.24V0Z" opacity=".5"></path>
                    <path d="M0,0V5.63C149.93,59,314.09,71.32,475.83,42.57c43-7.64,84.23-20.12,127.61-26.46,59-8.63,112.48,12.24,165.56,35.4C827.93,77.22,886,95.24,951.2,90c86.53-7,172.46-45.71,248.8-84.81V0Z"></path>
                </svg>
            </div>

            {/* Course Catalog Section */}
            <section className="section section-courses" id="courses">
                <div className="floating-shape parallax-shape" data-speed="0.3">
                    <div className="shape-blob shape-blob-1"></div>
                </div>
                <div className="floating-shape parallax-shape" data-speed="0.5">
                    <div className="shape-blob shape-blob-2"></div>
                </div>

                <div className="container">
                    <div className="section-header animate-child">
                        <span className="section-tag">
                            <span className="material-icons">school</span>
                            Course Catalog
                        </span>
                        <h2 className="section-title gradient-text">
                            Discover Your Path in Tech
                        </h2>
                        <p className="section-description">
                            From fundamentals to advanced concepts, find the perfect course to accelerate your career
                        </p>
                    </div>

                    {/* Enhanced Course filters */}
                    <div className="course-filters animate-child">
                        <div className="filters-wrapper">
                            <button 
                                className={`filter-btn ${activeFilter === 'all' ? 'active' : ''}`}
                                onClick={() => handleFilterClick('all')}
                            >
                                <span className="filter-icon">
                                    <span className="material-icons">apps</span>
                                </span>
                                <span className="filter-text">All Courses</span>
                                <span className="filter-count">24</span>
                            </button>
                            <button 
                                className={`filter-btn ${activeFilter === 'web' ? 'active' : ''}`}
                                onClick={() => handleFilterClick('web')}
                            >
                                <span className="filter-icon">
                                    <span className="material-icons">code</span>
                                </span>
                                <span className="filter-text">Web Development</span>
                                <span className="filter-count">8</span>
                            </button>
                            <button 
                                className={`filter-btn ${activeFilter === 'data' ? 'active' : ''}`}
                                onClick={() => handleFilterClick('data')}
                            >
                                <span className="filter-icon">
                                    <span className="material-icons">analytics</span>
                                </span>
                                <span className="filter-text">Data Science</span>
                                <span className="filter-count">6</span>
                            </button>
                            <button 
                                className={`filter-btn ${activeFilter === 'security' ? 'active' : ''}`}
                                onClick={() => handleFilterClick('security')}
                            >
                                <span className="filter-icon">
                                    <span className="material-icons">security</span>
                                </span>
                                <span className="filter-text">Cybersecurity</span>
                                <span className="filter-count">4</span>
                            </button>
                            <button 
                                className={`filter-btn ${activeFilter === 'cloud' ? 'active' : ''}`}
                                onClick={() => handleFilterClick('cloud')}
                            >
                                <span className="filter-icon">
                                    <span className="material-icons">cloud</span>
                                </span>
                                <span className="filter-text">Cloud Computing</span>
                                <span className="filter-count">3</span>
                            </button>
                            <button 
                                className={`filter-btn ${activeFilter === 'ai' ? 'active' : ''}`}
                                onClick={() => handleFilterClick('ai')}
                            >
                                <span className="filter-icon">
                                    <span className="material-icons">smart_toy</span>
                                </span>
                                <span className="filter-text">AI & ML</span>
                                <span className="filter-count">3</span>
                            </button>
                        </div>
                    </div>

                    <div className="animate-child">
                        <CourseSection filter={activeFilter} />
                    </div>
                </div>
            </section>

            {/* Wave Divider */}
            <div className="wave-divider">
                <svg viewBox="0 0 1200 120" preserveAspectRatio="none">
                    <path d="M321.39,56.44c58-10.79,114.16-30.13,172-41.86,82.39-16.72,168.19-17.73,250.45-.39C823.78,31,906.67,72,985.66,92.83c70.05,18.48,146.53,26.09,214.34,3V0H0V27.35A600.21,600.21,0,0,0,321.39,56.44Z"></path>
                </svg>
            </div>

            {/* About Section */}
            <section className="section section-about" id="about">
                <div className="container">
                    <AboutSection />
                </div>
            </section>

            {/* Geometric Divider */}
            <div className="geometric-divider">
                <div className="divider-shape"></div>
                <div className="divider-shape"></div>
                <div className="divider-shape"></div>
            </div>

            {/* Stats Section */}
            <section className="section section-stats" id="stats">
                <div className="stats-bg-pattern"></div>
                <div className="container">
                    <div className="section-header animate-child">
                        <span className="section-tag light">
                            <span className="material-icons">trending_up</span>
                            Our Impact
                        </span>
                        <h2 className="section-title">
                            Numbers That Speak Volumes
                        </h2>
                        <p className="section-description light">
                            Join thousands of successful graduates who've transformed their careers through our programs
                        </p>
                    </div>
                    <div className="animate-child">
                        <StatsSection />
                    </div>
                </div>
            </section>

            {/* Curved Divider */}
            <div className="curved-divider">
                <svg viewBox="0 0 1200 120" preserveAspectRatio="none">
                    <path d="M600,112.77C268.63,112.77,0,65.52,0,7.23V120H1200V7.23C1200,65.52,931.37,112.77,600,112.77Z"></path>
                </svg>
            </div>

            {/* News Section */}
            <section className="section section-news" id="news">
                <div className="news-decoration">
                    <div className="deco-line deco-line-1"></div>
                    <div className="deco-line deco-line-2"></div>
                </div>
                <div className="container">
                    <div className="section-header animate-child">
                        <span className="section-tag">
                            <span className="material-icons">newspaper</span>
                            News & Updates
                        </span>
                        <h2 className="section-title gradient-text-alt">
                            Stay in the Loop
                        </h2>
                        <p className="section-description">
                            Latest announcements, events, and insights from the tech education world
                        </p>
                    </div>
                    <div className="animate-child">
                        <NewsSection />
                    </div>
                </div>
            </section>

            {/* Zigzag Divider */}
            <div className="zigzag-divider">
                <svg viewBox="0 0 1200 120" preserveAspectRatio="none">
                    <path d="M0,0 L200,100 L400,0 L600,100 L800,0 L1000,100 L1200,0 L1200,120 L0,120 Z"></path>
                </svg>
            </div>

            {/* Contact Section */}
            <section className="section section-contact" id="contact">
                <div className="contact-bg-gradient"></div>
                <div className="container">
                    <div className="section-header animate-child">
                        <span className="section-tag light">
                            <span className="material-icons">mail</span>
                            Get in Touch
                        </span>
                        <h2 className="section-title">
                            Ready to Start Your Journey?
                        </h2>
                        <p className="section-description light">
                            Our team is here to guide you every step of the way
                        </p>
                    </div>
                    <div className="animate-child">
                        <ContactSection />
                    </div>
                </div>
            </section>
        </div>
    );
};

export default HomePage;
